    "1_product_title": {
      "name": "SOVEREIGN",
      "tagline": "The Affiliate Operating System & The Labyrinth. One Dashboard. Every Network. Unlimited Commissions. Escape the Maze, Claim the Crown."
    },
    "2_main_user_goal": {
      "primary_goal": "Maximize affiliate earnings while navigating the gamified Labyrinth to achieve Category Captain status, accessing aggregated commissions from every affiliate type (Direct, Network, Sub-Network) in one interface.",
      "problem_being_solved": "Affiliates are trapped in fragmented systems (Direct programs, Networks, Sub-networks, OPMs) with no unified view. They lack gamified progression, instant payouts, and AI optimization. Boutiqaat and traditional platforms offer linear, boring dashboards that don't enforce niche authority or visualize dark social attribution.",
      "key_value_proposition": "The only platform that aggregates ALL 10 affiliate model types (Direct, Network, Sub-Affiliate, Partner Platforms, Influencer platforms) into a single interface, with The Labyrinth gamification enforcing niche monogamy, AI Smart Routing optimizing commissions across all sources, and instant crypto/fiat payouts."
    },
    "3_tech_stack": {
      "frontend": ["Next.js 15.3.1", "TypeScript 5.4", "TailwindCSS 3.4", "shadcn/ui", "Framer Motion", "Three.js (for 3D Labyrinth)", "React-Three-Fiber", "Recharts", "TanStack Query", "zustand"],
      "backend": ["Supabase (PostgreSQL 15)", "Edge Functions (Deno)", "Realtime Subscriptions"],
      "authentication": ["Google OAuth 2.0", "Supabase Auth SSR", "JWT with Refresh Token Rotation", "Phone OTP (+971/+966)"],
      "database": "PostgreSQL 15 (Supabase) with Row Level Security",
      "hosting_infra": ["Vercel (Edge Network)", "Supabase (Frankfurt/Mumbai regions)", "Cloudflare R2 (Asset Storage)", "Upstash Redis (Rate Limiting)"],
      "integrations": [
        "Amazon Product Advertising API 5.0", 
        "AliExpress Portals API", 
        "CJ Affiliate API", 
        "Impact.com API", 
        "Awin API", 
        "ShareASale API", 
        "Rakuten API", 
        "Admitad API (MENA focus)", 
        "Skimlinks/ Sovrn (Sub-affiliate)", 
        "Post Affiliate Pro webhooks", 
        "Refersion API", 
        "LTK API", 
        "Tap Payments API", 
        "Circle USDC Payouts", 
        "WhatsApp Business API", 
        "Google Analytics 4"
      ]
    },
    "4_authentication_and_login": {
      "login_methods": ["Google OAuth (Primary)", "Email/Password with Magic Link", "Phone OTP (GCC +971/+966)"],
      "redirect_uri": "/labyrinth/entrance (First-time) OR /labyrinth/dashboard (Returning)",
      "session_handling": "JWT access token (15 min expiry) + Refresh token (7 days) stored in httpOnly cookies. Auto-refresh on 401. Session validation via Supabase SSR middleware.",
      "protected_routes": ["/labyrinth/*", "/dashboard/*", "/analytics/*", "/campaigns/*", "/smart-links/*", "/withdrawals/*", "/brand/*", "/admin/*"],
      "role_based_access": {
        "influencer": "Navigate Labyrinth, Earn Gold Dust, unlock corridors",
        "brand": "Place Minotaurs (challenges), Sponsor corridors",
        "admin": "Maze Architect - modify labyrinth structure"
      }
    },
    "5_backend_database_schema": {
      "tables": [
        {
          "name": "profiles",
          "fields": {
            "id": "UUID (PK, Auth user ID)",
            "email": "string (unique)",
            "full_name": "string",
            "avatar_url": "string",
            "role": "enum: influencer | brand | admin",
            "phone": "string (unique, GCC format)",
            "country": "enum: UAE | KSA | Kuwait | Qatar | Bahrain | Oman",
            "created_at": "timestamp (default now)",
            "status": "enum: pending_verification | active | suspended",
            "wallet_address": "string (USDC Polygon address)",
            "bank_iban": "string (encrypted)",
            "preferred_payout": "enum: instant_usdc | weekly_aed | monthly_bank"
          }
        },
        {
          "name": "labyrinth_progress",
          "fields": {
            "id": "UUID (PK)",
            "profile_id": "FK → profiles.id",
            "current_position_x": "int (grid coordinate)",
            "current_position_y": "int (grid coordinate)",
            "current_floor": "enum: basement | ground | upper | roof (0-3)",
            "niche_gate": "enum: Beauty | Tech | Fashion_Modest | Fashion_Luxury | Fitness | Home_Decor | Watches | Kids | Food | Gaming | Finance (The chosen entrance)",
