            "gold_dust_balance": "int (gamification currency)",
            "authority_score": "int (0-100, determines movement speed)",
            "tier": "enum: Bronze | Silver | Gold | Platinum",
            "category_captain": "boolean (default false, true = reached center)",
            "walls_hit": "int (dead ends encountered - anti-gaming metric)",
            "teleports_used": "int (commission arbitrage count)",
            "minotaur_encounters": "int (failed generalist attempts)",
            "locked_until": "timestamp (90 days from niche selection)",
            "labyrinth_status": "enum: wandering | trapped | teleported | crowned"
          }
        },
        {
          "name": "affiliate_sources",
          "fields": {
            "id": "UUID (PK)",
            "source_type": "enum: direct_merchant | affiliate_network | sub_affiliate_network | partner_platform | tracking_software | influencer_platform | cashback_portal | coupon_site | marketplace_directory | opm_agency",
            "name": "string (e.g., 'Amazon Associates', 'CJ Affiliate', 'Skimlinks', 'Acceleration Partners')",
            "api_endpoint": "string",
            "api_key_encrypted": "string",
            "commission_structure": "jsonb (category rates)",
            "is_sub_affiliate": "boolean (takes cut from top)",
            "active": "boolean",
            "last_sync": "timestamp",
            "payout_min": "int (AED)",
            "cookie_duration": "int (days)",
            "maze_corridor_color": "string (hex for viz)"
          }
        },
        {
          "name": "products",
          "fields": {
            "id": "UUID (PK)",
            "source_id": "FK → affiliate_sources.id",
            "external_id": "string (Network SKU)",
            "name": "string (indexed)",
            "description": "text",
            "category": "string (unified taxonomy, must match niche_gate)",
            "price_aed": "decimal(10,2)",
            "commission_percent": "decimal(5,2)",
            "commission_aed": "decimal(10,2)",
            "epc": "decimal(10,2)",
            "images": "text[] (URLs)",
            "stock_status": "enum: in_stock | low | out",
            "trending_score": "int (0-100)",
            "available_in": "text[] (country codes)",
            "is_high_ticket": "boolean (for luxury corridors)",
            "created_at": "timestamp"
          }
        },
        {
          "name": "smart_links",
          "fields": {
            "id": "UUID (PK)",
            "profile_id": "FK → profiles.id",
            "product_id": "FK → products.id",
            "short_code": "string (unique, 8 chars, e.g., 'nx.ae/Ab3x9k')",
            "destination_url": "text (Final resolved URL)",
            "routing_logic": "jsonb (smart routing hierarchy)",
            "dark_post_variant": "enum: emirati_elite | labor | tourist | generic (The maze shadow path)",
            "total_clicks": "int (default 0)",
            "total_conversions": "int (default 0)",
            "revenue_generated": "decimal(12,2)",
            "gold_dust_generated": "int (gamification value)",
            "created_at": "timestamp",
            "expires_at": "timestamp",
            "is_golden_bridge": "boolean (direct deal = skips maze walls)"
