{
  "name": "SOVEREIGN",
  "description": "The Affiliate Operating System & The Labyrinth. A unified dashboard aggregating all affiliate networks with gamified progression and AI-driven smart routing.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum NicheGate {
  Beauty = 'Beauty',
  Tech = 'Tech',
  Fashion_Luxury = 'Fashion Luxury',
  Fitness = 'Fitness',
  Home_Decor = 'Home Decor',
  Gaming = 'Gaming'
}

export enum Floor {
  Basement = 'Basement',
  Ground = 'Ground',
  Upper = 'Upper',
  Roof = 'Roof'
}

export enum Tier {
  Bronze = 'Bronze',
  Silver = 'Silver',
  Gold = 'Gold',
  Platinum = 'Platinum'
}

export interface UserProgress {
  niche: NicheGate | null;
  floor: Floor;
  tier: Tier;
  goldDust: number;
  authorityScore: number;
  earningsAED: number;
  isCategoryCaptain: boolean;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, useLocation } from 'react-router-dom';
import { NicheGate, Floor, Tier, UserProgress } from './types';
import LandingPage from './pages/LandingPage';
import GateSelection from './pages/GateSelection';
import LabyrinthDashboard from './pages/LabyrinthDashboard';
import AlchemistPage from './pages/AlchemistPage';
import TreasuryPage from './pages/TreasuryPage';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [user, setUser] = useState<UserProgress>({
    niche: null,
    floor: Floor.Basement,
    tier: Tier.Bronze,
